const items = $input.all();
const hoje = new Date();
return items.filter(item => {
  const lead = item.json;
  if (lead.status === 'FECHADO' || lead.status === 'DESCARTADO') return false;
  if (!lead.data_entrada) return false;
  const dias = (hoje - new Date(lead.data_entrada)) / (1000*60*60*24);
  return dias >= 30 && dias <= 180 && lead.classificacao !== 'HOT';
});

